/// Hash parameters found by brute-force and verified by z4 SMT solver.
const HASH_A: u32 = 0x7ac3_dd23;
const HASH_B: u32 = 0xe2df_c703;
const HASH_C: u32 = 0;
const TABLE_SIZE: usize = 126;

/// Encode CSI intermediate bytes as a single u8 for hashing.
///
/// Single-byte intermediates use their ASCII value directly.
/// Special encodings:
/// - `0x00` = no intermediates (standard CSI)
/// - `0x01` = `?$` (two-byte DEC private mode request)
#[inline]
pub(crate) fn encode_intermediates(intermediates: &[u8]) -> u8 {
    match intermediates {
        [] => 0x00,
        [b'?', b'$'] => 0x01,
        [single] => *single,
        _ => 0xFF, // unrecognized
    }
}

/// Compute the hash index for a CSI key.
#[inline]
pub(crate) fn csi_hash(intermediate_enc: u8, final_byte: u8) -> usize {
    let key = (u32::from(intermediate_enc) << 8) | u32::from(final_byte);
    (key.wrapping_mul(HASH_A).wrapping_add(HASH_B) >> HASH_C) as usize % TABLE_SIZE
}

